  describe('state invariants (stateful PBT)', () => {
    it('always: boards have required fields', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('open'), input: fc.record({ step_ref: fc.string({ minLength: 1, maxLength: 50 }), anonymous: fc.boolean(), shortlist_size: fc.integer({ min: 1, max: 1000 }) }) }),
              fc.record({ action: fc.constant('submitIdea'), input: fc.record({ board: fc.string(), idea_ref: fc.string({ minLength: 1, maxLength: 50 }), submitter_ref: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('forkIdea'), input: fc.record({ board: fc.string(), parent_idea_ref: fc.string({ minLength: 1, maxLength: 50 }), fork_idea_ref: fc.string({ minLength: 1, maxLength: 50 }), submitter_ref: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('endorseIdea'), input: fc.record({ board: fc.string(), idea_ref: fc.string({ minLength: 1, maxLength: 50 }), voter_ref: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('closeSubmission'), input: fc.record({ board: fc.string() }) }),
              fc.record({ action: fc.constant('shortlist'), input: fc.record({ board: fc.string(), idea_refs: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('close'), input: fc.record({ board: fc.string() }) }),
              fc.record({ action: fc.constant('getIdeas'), input: fc.record({ board: fc.string() }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = brainstormBoardHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(brainstormBoardHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: closed board has empty output', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('open'), input: fc.record({ step_ref: fc.string({ minLength: 1, maxLength: 50 }), anonymous: fc.boolean(), shortlist_size: fc.integer({ min: 1, max: 1000 }) }) }),
              fc.record({ action: fc.constant('submitIdea'), input: fc.record({ board: fc.string(), idea_ref: fc.string({ minLength: 1, maxLength: 50 }), submitter_ref: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('forkIdea'), input: fc.record({ board: fc.string(), parent_idea_ref: fc.string({ minLength: 1, maxLength: 50 }), fork_idea_ref: fc.string({ minLength: 1, maxLength: 50 }), submitter_ref: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('endorseIdea'), input: fc.record({ board: fc.string(), idea_ref: fc.string({ minLength: 1, maxLength: 50 }), voter_ref: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('closeSubmission'), input: fc.record({ board: fc.string() }) }),
              fc.record({ action: fc.constant('shortlist'), input: fc.record({ board: fc.string(), idea_refs: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('close'), input: fc.record({ board: fc.string() }) }),
              fc.record({ action: fc.constant('getIdeas'), input: fc.record({ board: fc.string() }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = brainstormBoardHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(brainstormBoardHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
                // Never: closed board has empty output
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

